import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../utils/api';
import { motion } from 'framer-motion';
import styles from './TournamentsPage.module.css';

// Countdown timer component
function Countdown({ endDate }) {
  const [timeLeft, setTimeLeft] = useState('');

  useEffect(() => {
    const calc = () => {
      const diff = new Date(endDate) - new Date();
      if (diff <= 0) return setTimeLeft('Ended');
      const d = Math.floor(diff / 86400000);
      const h = Math.floor((diff % 86400000) / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      setTimeLeft(d > 0 ? `${d}d ${h}h` : `${h}h ${m}m`);
    };
    calc();
    const i = setInterval(calc, 60000);
    return () => clearInterval(i);
  }, [endDate]);

  return <span className={styles.countdown}>{timeLeft}</span>;
}

const STATUS_COLORS = {
  open: '#3FB950',
  running: '#58A6FF',
  scored: '#D29922',
  completed: '#BC8CFF',
};

export default function TournamentsPage() {
  const [tournaments, setTournaments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const navigate = useNavigate();

  const load = useCallback(async () => {
    try {
      const data = await api('/tournaments');
      setTournaments(data?.tournaments || data || []);
    } catch { /* toast auto-handled */ }
    setLoading(false);
  }, []);

  useEffect(() => { load(); }, [load]);

  const filtered = filter === 'all'
    ? tournaments
    : tournaments.filter(t => t.status === filter);

  return (
    <div className={styles.page}>
      <div className={styles.header}>
        <div>
          <h1 className={styles.title}>Tournaments</h1>
          <p className={styles.subtitle}>Compete with strategies. Win revenue share.</p>
        </div>
      </div>

      <div className={styles.filters}>
        {['all', 'open', 'running', 'scored', 'completed'].map(f => (
          <button
            key={f}
            className={`${styles.filterPill} ${filter === f ? styles.filterActive : ''}`}
            onClick={() => setFilter(f)}
          >
            {f === 'all' ? 'All' : f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>

      {loading ? (
        <div className={styles.cardGrid}>
          {[1, 2, 3].map(i => <div key={i} className={styles.skeleton} />)}
        </div>
      ) : filtered.length === 0 ? (
        <div className={styles.emptyState}>
          <p className={styles.emptyTitle}>No tournaments {filter !== 'all' ? `(${filter})` : ''}</p>
          <p className={styles.emptyDesc}>Check back soon for upcoming competitions.</p>
        </div>
      ) : (
        <div className={styles.cardGrid}>
          {filtered.map((t, i) => (
            <motion.div
              key={t.id}
              className={styles.card}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.05 }}
              onClick={() => navigate(`/tournaments/${t.id}`)}
            >
              <div className={styles.cardHeader}>
                <span
                  className={styles.statusBadge}
                  style={{ background: STATUS_COLORS[t.status] + '22', color: STATUS_COLORS[t.status] }}
                >
                  {t.status?.toUpperCase()}
                </span>
                {t.status === 'open' && t.end_date && <Countdown endDate={t.end_date} />}
              </div>
              <h3 className={styles.cardTitle}>{t.name}</h3>
              <p className={styles.cardDesc}>{t.description}</p>

              <div className={styles.prizeRow}>
                <div className={styles.prize}><span className={styles.prizeIcon} style={{ color: '#D29922' }}>1st</span> 5% rev share</div>
                <div className={styles.prize}><span className={styles.prizeIcon} style={{ color: '#8B949E' }}>2nd</span> 3%</div>
                <div className={styles.prize}><span className={styles.prizeIcon} style={{ color: '#CD7F32' }}>3rd</span> 1%</div>
              </div>

              <div className={styles.cardMeta}>
                <span>{t.start_date?.split('T')[0]} - {t.end_date?.split('T')[0]}</span>
                <span>{t.universe || 'us,crypto'}</span>
              </div>

              <button
                className={styles.cardAction}
                onClick={e => { e.stopPropagation(); navigate(`/tournaments/${t.id}`); }}
              >
                {t.status === 'open' ? 'Enter Tournament' : 'View Results'}
              </button>
            </motion.div>
          ))}
        </div>
      )}

      <div className={styles.scoringInfo}>
        <h4>Scoring Formula</h4>
        <p>60% Sharpe Ratio + 25% Consistency + 15% Max Drawdown (inverted). Min 30 trades.</p>
      </div>
    </div>
  );
}
